input.code:
build for javascript backend
database is local memory

/*
  Counter API
  Append-only log: each increment saves a row,
  the count of rows IS the current counter value.
  Reset clears all rows and returns zero.

  Endpoints:
    GET  /api/count     → { count: N }
    POST /api/increment → adds a tick, returns { count: N }
    POST /api/reset     → returns { count: 0 }
*/

# Data

create a CounterEvents table:
  event_type, default 'increment'

# Backend

when user calls GET /api/count:
  total = count of id from CounterEvents
  send back { count: total }

when user calls POST /api/increment:
  tick = { event_type: 'increment' }
  save tick as new CounterEvents
  new_total = count of id from CounterEvents
  send back { count: new_total }

when user calls POST /api/reset:
  send back { count: 0 }
